async (params, browser) => {
  // Open movie page
  await browser.open(`${params.movie_url}`)

  // Wait for movie page to load
  await browser.waitForSelector('h1, [data-qa=\'score-panel\'], [class*=\'scoreboard\'], rt-button', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract movie details
  const movie_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [class*="scoreboard"] h1, [data-qa="score-panel-title"]'); const tomatometerEl = document.querySelector('rt-button[slot="criticsScore"] rt-text, [data-qa="tomatometer"], score-board[tomatometerscore], [class*="tomatometer"] span'); const audienceEl = document.querySelector('rt-button[slot="audienceScore"] rt-text, [data-qa="audience-score"], score-board[audiencescore], [class*="audience-score"] span'); const consensusEl = document.querySelector('[data-qa="critics-consensus"], [class*="consensus"], p[data-qa="what-to-know"]'); const synopsisEl = document.querySelector('[data-qa="movie-info-synopsis"], [class*="synopsis"], #movieSynopsis, [data-qa="section:media-scorecard"] p'); const imgEl = document.querySelector('[data-qa="poster-image"] img, .posterImage img, img[class*="posterImage"]'); const infoEls = document.querySelectorAll('[data-qa="movie-info-item"], li[class*="info-item"], [class*="category-wrap"]'); const info = {}; infoEls.forEach(function(el) { const labelEl = el.querySelector('[data-qa="movie-info-item-label"], b, [class*="label"]'); const valueEl = el.querySelector('[data-qa="movie-info-item-value"], span, [class*="value"]'); if (labelEl && valueEl) { info[labelEl.textContent.trim().replace(':', '')] = valueEl.textContent.trim(); } }); const castEls = document.querySelectorAll('[data-qa="cast-item"], [class*="cast-item"], [class*="castSection"] a'); const cast = []; castEls.forEach(function(el) { const nameEl = el.querySelector('[data-qa="cast-item-name"], [class*="name"], a'); const charEl = el.querySelector('[data-qa="cast-item-character"], [class*="character"]'); cast.push({ name: nameEl ? nameEl.textContent.trim() : el.textContent.trim(), character: charEl ? charEl.textContent.trim() : '' }); }); let scoreboard = document.querySelector('score-board, [class*="scoreboard"]'); let tomatometerState = ''; let audienceState = ''; if (scoreboard) { tomatometerState = scoreboard.getAttribute('tomatometerstate') || ''; audienceState = scoreboard.getAttribute('audiencestate') || ''; } return { title: titleEl ? titleEl.textContent.trim() : '', tomatometer: tomatometerEl ? tomatometerEl.textContent.trim() : '', tomatometer_state: tomatometerState, audience_score: audienceEl ? audienceEl.textContent.trim() : '', audience_state: audienceState, critics_consensus: consensusEl ? consensusEl.textContent.trim().substring(0, 500) : '', synopsis: synopsisEl ? synopsisEl.textContent.trim().substring(0, 1000) : '', info: info, cast: cast.slice(0, 10), image: imgEl ? imgEl.getAttribute('src') : '', url: window.location.href }`)

  return movie_data
}
